import{getFirestore,doc,getDoc,setDoc,updateDoc,increment,serverTimestamp}from"https://www.gstatic.com/firebasejs/12.1.0/firebase-firestore.js";import{app}from"./firebase.min.js";const db=getFirestore(app);export async function ensureUserCredits(e){const t=doc(db,"credits",e),r=await getDoc(t),s={usedCredits:0,maxCredits:10,lastUpdated:serverTimestamp()};if(r.exists()){const e=r.data()||{},s={};let i=!1;"number"!=typeof e.usedCredits&&(s.usedCredits=0,i=!0),"number"!=typeof e.maxCredits&&(s.maxCredits=10,i=!0),i&&(s.lastUpdated=serverTimestamp(),await updateDoc(t,s))}else await setDoc(t,s);return t}export async function canUseCredits(e){const t=await ensureUserCredits(e),r=await getDoc(t);if(!r.exists())return!1;const s=r.data()||{};return Number(s.usedCredits||0)<Number(s.maxCredits||0)}export async function consumeCredit(e){const t=await ensureUserCredits(e),r=await getDoc(t);if(!r.exists())throw new Error("Credits document does not exist.");const s=r.data()||{};if(Number(s.usedCredits||0)>=Number(s.maxCredits||0))throw new Error("No credits remaining.");await updateDoc(t,{usedCredits:increment(1),lastUpdated:serverTimestamp()})}export async function addCredits(e,t){const r=await ensureUserCredits(e),s=Number(t);if(!Number.isFinite(s)||s<=0)throw new Error("creditsToAdd must be a positive number.");await updateDoc(r,{maxCredits:increment(s),lastUpdated:serverTimestamp()})}export async function getCreditInfo(e){const t=await ensureUserCredits(e),r=await getDoc(t);if(!r.exists())return null;const s=r.data()||{},i=Number(s.usedCredits||0),a=Number(s.maxCredits||0);return{usedCredits:i,maxCredits:a,remainingCredits:Math.max(a-i,0),lastUpdated:s.lastUpdated||null}}